Here's how to test `DataFetcher` with modern MSTest 3.x patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        var mock = new MockHandler(handler);
        return new DataFetcher(new HttpClient(mock));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var fetcher = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var fetcher = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CallerCancels_ThrowsOperationCanceled()
    {
        var fetcher = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct); // simulate slow server
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // guard against hangs — cancels via TestContext.CancellationToken
    public async Task FetchAsync_Timeout_IsCancelledCooperatively()
    {
        var fetcher = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        // Pass TestContext.CancellationToken so [Timeout] can cancel the call
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // Minimal HttpMessageHandler stub — no mocking library needed
    private sealed class MockHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => handler(request, cancellationToken);
    }
}
```

**Key takeaways:**

| Pattern | Why |
|---|---|
| `sealed class` | Performance + design clarity |
| `TestContext` via constructor | Inject once, use `CancellationToken` everywhere |
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest fires the token, your code responds |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]`, lets you inspect the exception |
| `MockHandler` stub | Avoids mocking-library dependency for `HttpClient` |

The critical pattern: **always flow `TestContext.CancellationToken`** into async calls inside `[Timeout]` tests. Without it, the timeout fires but the test hangs because nothing observes the cancellation.
